        acc0 = lmac8(acc0, rhs_v16, 0, 0x76543210, lhs_v16.extract<8>(1), 0, 0x0);
        rhs_v16 = rhs_v16.insert(1, aie::load_v<8>(rhs));
        rhs += w2;
