            connect<cascade> (k[i].out[0],k[i+1].in[1]);
            connect<stream> (k[NChunks-1].out[0],out);


            // Input Streams connections
            for(int i=0;i<NChunks;i++)
            connect<stream>(in[i],k[i].in[0]);

        };
    };


