				k[i]=kernel::create(mean_dev_norm_last<K_COL,K_ROW,NUM>);
				dimensions(k[i].in[0])={K_ROW*K_COL};//elements
				dimensions(k[i].out[0])={K_ROW*K_COL};//elements
				source(k[i])="mean_dev_norm_last.cc";
			}

