template<int FrameLength,int VectorLength>
void passthrough_buffer(adf::input_buffer<=<int32, adf::extents<FrameLength>> &__restrict in, adf::output_buffer<int32, adf::extents<FrameLength>> &__restrict out)
{
    int32 i;
