    set_sat();
};

void bf8x8_lst_api(input_window<cint16> * restrict c_input, input_window<cint16> * restrict x_input, input_stream_cacc48 * cascade_in, output_window<cint16> * restrict c_output)
{
    // Loop Through the PRBs
    for (unsigned prbcnt=0; prbcnt<NUM_PRBS; ++prbcnt)
        chess_prepare_for_pipelining
    {
        //---------------------------------------
        // Every Loop Deals with Two Subcarriers
        //---------------------------------------
        for (unsigned i=0; i<12; ++i)  
        chess_prepare_for_pipelining
        chess_unroll_loop(2)
        {
