            auto acc1 = readincr_v<8>(cascade_in);
            acc1      = aie::mac(acc1, dat0[0], bufa0); bufb0 = window_readincr_v8(c_input); 
            acc1      = aie::mac(acc1, dat0[1], bufa1); bufb1 = window_readincr_v8(c_input); 

