#include <adf.h>
#include "para_L0.h"
#include <stdio.h>
using namespace adf;


template <int COL_OFFSET, int ROW_OFFSET>
class simpleGraph_k0_L0_B4_A0_C10: public graph {
  private:
    kernel mm[L0_NUM_KERNEL];

  public:
    port<input> in[L0_NUM_KERNEL];
    port<input> weights_offset;
    port<output> out;

    simpleGraph_k0_L0_B4_A0_C10() {

      mm[0] = kernel::create(mm0_kernel0_L0_B0_A0_C10);
      source(mm[0]) = "mm0_kernel0_L0_B0_A0_C10.cc";
      mm[1] = kernel::create(mm0_kernel1_L0_B1_A0_C10);
      source(mm[1]) = "mm0_kernel1_L0_B1_A0_C10.cc";
      mm[2] = kernel::create(mm0_kernel1_L0_B2_A0_C10);
      source(mm[2]) = "mm0_kernel1_L0_B2_A0_C10.cc";
      mm[3] = kernel::create(mm0_kernel2_L0_B3_A0_C10);
      source(mm[3]) = "mm0_kernel2_L0_B3_A0_C10.cc";

      for (int i=0; i<L0_NUM_KERNEL;i++){
        runtime<ratio>(mm[i]) = 2.0;
        if ((ROW_OFFSET%2)==0){
          adf::location<kernel>(mm[i]) = adf::tile(COL_OFFSET+i,ROW_OFFSET);
        }
        else{
          adf::location<kernel>(mm[i]) = adf::tile(COL_OFFSET-i,ROW_OFFSET);
        }
      }

      for (int i=0; i<L0_NUM_KERNEL;i++){
        if ((ROW_OFFSET%2)==0){
          location<buffer>(mm[i].in[0]) =
          { address(COL_OFFSET+i, ROW_OFFSET+1, 0x5000), 
            address(COL_OFFSET+i, ROW_OFFSET+1, 0x7000)};
          location<stack>(mm[i]) = address(COL_OFFSET+i, ROW_OFFSET, 0x0000);
        }
        else{
          location<buffer>(mm[i].in[0]) =
          { address(COL_OFFSET-i, ROW_OFFSET-1, 0x5000), 
            address(COL_OFFSET-i, ROW_OFFSET-1, 0x7000)};
          location<stack>(mm[i]) = address(COL_OFFSET-i, ROW_OFFSET, 0x0000);
        }
      }


      for (int i=0; i<L0_NUM_KERNEL;i++){
        connect<window<L0_h1*L0_w1>>(in[i], mm[i].in[0]);
      }

      connect<parameter>(weights_offset, async(mm[0].in[1]));

      for (int i=0; i<L0_NUM_KERNEL;i++){
        if(i==L0_NUM_KERNEL-1){
          connect<stream>(mm[i].out[0], out);
        }
        else{
          connect<cascade>(mm[i].out[0], mm[i+1].in[1]);
        }
      }


    };

};

