                                                       {.dimension=2,.stride=1,.wrap=13}} };

    MT0 = shared_buffer<bfloat16>::create({16*16*13},1,1);
    write_access(MT0.in[0]) = tiling(bdw0);
    read_access(MT0.out[0]) = tiling(bdr0);
