    void run(input_stream<int8>* __restrict in, output_stream<int8>* __restrict out);
};

void fir_filter_int8_stream_only_2::run(input_stream<int8>* __restrict in, output_stream<int8>* __restrict out) {
    auto coeff = aie::load_v<32>(coeffs);
    aie::vector<int8, 32> state = aie::load_v<32>(delay_line);
    aie::accum<acc48, 32> acc = aie::zeros<acc48, 32>();
    aie::accum<acc48, 32> result = aie::zeros<acc48, 32>();
    aie::vector<int8, 32> phase_acc = aie::broadcast<int8, 32>(0);
    aie::vector<int8, 32> phase_step = aie::broadcast<int8, 32>(2);
    for (unsigned frame = 0; frame < 32; ++frame)
        chess_prepare_for_pipelining
        chess_loop_count(32, 32)
    {
        auto vin = readincr_v<32>(in);
        state = aie::shuffle_up(state, vin, 1);
        acc = aie::mul(state, coeff);
        result = aie::add(acc, aie::broadcast<int8, 32>(0));
        writeincr(out, result.template to_vector<int8>());
    }
}

