  v8int32 *restrict ptr_img_out = (v8int32 *)img_out;

  v16int32 data_buf;
  v8int32 data_out;
  v8acc80 acc;

  v8int32 *restrict ptr_coeff_buffer = (v8int32 *)kernel_coeff;
  v8int32 kernel_vec0 = *(ptr_coeff_buffer)++; // 1st 8 kernel values (0 .. 7)
  v8int32 kernel_vec1 = *(ptr_coeff_buffer);   // last kernel value (8)

  v8int32 *restrict ptr0 = ptr_img_buffer;
  v8int32 *restrict ptr1 = ptr_img_buffer + 1 * 272 / PARALLEL_FACTOR_32b;
  v8int32 *restrict ptr2 = ptr_img_buffer + 2 * 272 / PARALLEL_FACTOR_32b;
  v8int32 *restrict ptr_out = ptr_img_out;

  // 3x3 kernel positions
  //
  // 0 1 2
  // 3 4 5
  // 6 7 8

  for (int i = 0; i < 8; i++)
    chess_prepare_for_pipelining chess_loop_range(16, 16) {
      for (int j = 0; j < 256; j += PARALLEL_FACTOR_32b) // 8x samples per loop
        chess_prepare_for_pipelining chess_loop_range(32, 32) {
